// src/App.js
import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import AppRoutes from "./routes/AppRoutes";

function App() {
  const userRole = localStorage.getItem("role");

  return (
    <Router>
      <Routes>
        {/* Root route */}
        <Route
          path="/"
          element={userRole ? <Navigate to={`/${userRole}`} replace /> : <AppRoutes.Public.Login />}
        />

        {/* Registration route */}
        <Route path="/register" element={<AppRoutes.Public.Register />} />

        {/* All protected routes */}
        <Route path="/*" element={<AppRoutes.Protected />} />

        {/* Fallback 404 */}
        <Route path="*" element={<AppRoutes.NotFound />} />
      </Routes>
    </Router>
  );
}

export default App;
